import re
from typing import Optional, Union


class ASTNode:
    def __init__(
        self,
        node_type: str,
        value: Optional[float] = None,
        op: Optional[str] = None,
        left: Optional["ASTNode"] = None,
        right: Optional["ASTNode"] = None,
        operand: Optional["ASTNode"] = None,
    ):
        self.type = node_type
        self.value = value
        self.op = op
        self.left = left
        self.right = right
        self.operand = operand

    def __repr__(self):
        if self.type == "number":
            return f"ASTNode(type=number, value={self.value})"
        elif self.type == "binop":
            return f"ASTNode(type=binop, op={self.op!r}, left={self.left}, right={self.right})"
        elif self.type == "unary":
            return f"ASTNode(type=unary, op={self.op!r}, operand={self.operand})"
        return f"ASTNode(type={self.type!r})"


class Tokenizer:
    def __init__(self, expression: str):
        self.expression = expression
        self.pos = 0
        self.tokens = []
        self._tokenize()

    def _tokenize(self):
        patterns = [
            (r"\s+", None),
            (r"\d+\.?\d*", "NUMBER"),
            (r"\+", "PLUS"),
            (r"-", "MINUS"),
            (r"\*", "MULTIPLY"),
            (r"/", "DIVIDE"),
            (r"\(", "LPAREN"),
            (r"\)", "RPAREN"),
        ]

        pos = 0
        while pos < len(self.expression):
            match = None
            for pattern, token_type in patterns:
                regex = re.compile(pattern)
                match = regex.match(self.expression, pos)
                if match:
                    if token_type:
                        value = match.group(0)
                        if token_type == "NUMBER":
                            value = float(value)
                        self.tokens.append((token_type, value))
                    pos = match.end()
                    break

            if not match:
                raise ValueError(
                    f"Invalid token at position {pos}: {self.expression[pos]!r}"
                )

        self.tokens.append(("EOF", None))

    def current(self):
        return self.tokens[self.pos]

    def consume(self, expected_type: Optional[str] = None):
        token = self.current()
        if expected_type and token[0] != expected_type:
            raise ValueError(f"Expected {expected_type}, got {token[0]}")
        self.pos += 1
        return token


class Parser:
    def __init__(self, tokenizer: Tokenizer):
        self.tokenizer = tokenizer

    def parse(self) -> ASTNode:
        if self.tokenizer.current()[0] == "EOF":
            raise ValueError("Empty expression")

        result = self._expression()

        if self.tokenizer.current()[0] != "EOF":
            raise ValueError(f"Unexpected token: {self.tokenizer.current()[1]}")

        return result

    def _expression(self) -> ASTNode:
        return self._additive()

    def _additive(self) -> ASTNode:
        left = self._multiplicative()

        while self.tokenizer.current()[0] in ("PLUS", "MINUS"):
            op_token = self.tokenizer.consume()
            op = "+" if op_token[0] == "PLUS" else "-"
            right = self._multiplicative()
            left = ASTNode(node_type="binop", op=op, left=left, right=right)

        return left

    def _multiplicative(self) -> ASTNode:
        left = self._unary()

        while self.tokenizer.current()[0] in ("MULTIPLY", "DIVIDE"):
            op_token = self.tokenizer.consume()
            op = "*" if op_token[0] == "MULTIPLY" else "/"
            right = self._unary()
            left = ASTNode(node_type="binop", op=op, left=left, right=right)

        return left

    def _unary(self) -> ASTNode:
        if self.tokenizer.current()[0] == "MINUS":
            self.tokenizer.consume()
            operand = self._unary()
            return ASTNode(node_type="unary", op="-", operand=operand)

        return self._primary()

    def _primary(self) -> ASTNode:
        token = self.tokenizer.current()

        if token[0] == "NUMBER":
            self.tokenizer.consume()
            return ASTNode(node_type="number", value=token[1])

        if token[0] == "LPAREN":
            self.tokenizer.consume()
            node = self._expression()

            if self.tokenizer.current()[0] != "RPAREN":
                raise ValueError("Unmatched parenthesis")

            self.tokenizer.consume()
            return node

        raise ValueError(f"Unexpected token: {token[1]}")


def parse(expression: str) -> ASTNode:
    if not expression or not expression.strip():
        raise ValueError("Empty expression")

    tokenizer = Tokenizer(expression)
    parser = Parser(tokenizer)
    return parser.parse()


def evaluate(node: ASTNode) -> float:
    if node.type == "number":
        assert node.value is not None
        return node.value

    if node.type == "unary":
        assert node.operand is not None
        assert node.op is not None
        operand_value = evaluate(node.operand)
        if node.op == "-":
            return -operand_value
        raise ValueError(f"Unknown unary operator: {node.op}")

    if node.type == "binop":
        assert node.left is not None
        assert node.right is not None
        assert node.op is not None
        left_value = evaluate(node.left)
        right_value = evaluate(node.right)

        if node.op == "+":
            return left_value + right_value
        elif node.op == "-":
            return left_value - right_value
        elif node.op == "*":
            return left_value * right_value
        elif node.op == "/":
            if right_value == 0:
                raise ZeroDivisionError("Division by zero")
            return left_value / right_value
        else:
            raise ValueError(f"Unknown binary operator: {node.op}")

    raise ValueError(f"Unknown node type: {node.type}")
